import Image from "next/image";
import { Project } from "@/lib/types";
import { ArrowIcon, GitHubIcon } from "../ui/Icons";

interface ProjectCardProps {
  project: Project;
}

export function ProjectCard({ project }: ProjectCardProps) {
  return (
    <article className="group flex flex-col lg:flex-row gap-8 lg:gap-12 items-center p-4 -m-4 rounded-[--radius-lg] transition-[transform,box-shadow] duration-[--duration-normal] ease-[--ease-out] hover:scale-[1.01] hover:shadow-lg focus-within:scale-[1.01] focus-within:shadow-lg motion-reduce:hover:!scale-100 motion-reduce:focus-within:!scale-100">
      {/* Project Image */}
      <div className="relative w-full lg:w-[600px] aspect-square shrink-0 bg-bg-elevated border-2 border-border-subtle rounded-[--radius-md] overflow-hidden transition-all duration-[--duration-normal] ease-[--ease-out] group-hover:border-accent/40 group-hover:shadow-card">
        <Image
          src={project.image}
          alt={`${project.title} project screenshot`}
          fill
          className="object-contain p-8 lg:p-14 transition-transform duration-[--duration-slow] ease-[--ease-out] group-hover:scale-[1.03]"
          sizes="(max-width: 1024px) 100vw, 600px"
        />
        {project.tag && (
          <span className="absolute top-4 left-4 bg-bg-tag/80 backdrop-blur-sm text-text-primary font-body font-medium text-sm px-4 py-2 rounded-full border border-border-subtle">
            {project.tag}
          </span>
        )}
      </div>

      {/* Project Content */}
      <div className="flex flex-col gap-10 flex-1 min-w-0">
        <div className="flex flex-col gap-6">
          {/* Title & Description */}
          <div className="flex flex-col gap-3">
            <h3 className="font-body font-semibold text-2xl md:text-[32px] text-text-primary leading-[1.3]">
              {project.title}
            </h3>
            <p className="font-body text-lg text-text-secondary leading-[1.6]">
              {project.description}
            </p>
          </div>

          {/* Project Info */}
          <div className="flex flex-col gap-3">
            <h4 className="font-body font-semibold text-xs text-text-muted uppercase tracking-[0.1em]">
              Project Info
            </h4>
            <dl className="border-b border-border">
              {project.client && (
                <div className="flex items-center justify-between py-3.5 border-t border-border">
                  <dt className="font-body font-medium text-sm text-text-secondary">
                    Client
                  </dt>
                  <dd className="font-body font-medium text-sm text-text-primary">
                    {project.client}
                  </dd>
                </div>
              )}
              <div className="flex items-center justify-between py-3.5 border-t border-border">
                <dt className="font-body font-medium text-sm text-text-secondary">
                  Year
                </dt>
                <dd className="font-body font-medium text-sm text-text-primary">
                  {project.year}
                </dd>
              </div>
              <div className="flex items-center justify-between py-3.5 border-t border-border">
                <dt className="font-body font-medium text-sm text-text-secondary">
                  Role
                </dt>
                <dd className="font-body font-medium text-sm text-text-primary">
                  {project.role}
                </dd>
              </div>
            </dl>
          </div>
        </div>

        {/* Action Links */}
        <div className="flex items-start gap-6">
          {project.liveUrl && (
            <a
              href={project.liveUrl}
              className="group/link flex flex-col gap-1"
              target="_blank"
              rel="noopener noreferrer"
            >
              <span className="flex items-center gap-1.5 font-body font-bold text-sm text-accent uppercase tracking-wide transition-colors duration-[--duration-fast] group-hover/link:text-accent-hover">
                Live Demo
                <ArrowIcon className="size-4 text-accent transition-transform duration-[--duration-fast] ease-[--ease-out] group-hover/link:translate-x-0.5 group-hover/link:-translate-y-0.5" />
              </span>
              <span className="h-0.5 w-full bg-accent/60 transition-all duration-[--duration-fast] ease-[--ease-out] group-hover/link:bg-accent-hover" />
            </a>
          )}
          {project.githubUrl && (
            <a
              href={project.githubUrl}
              className="group/link flex flex-col gap-1"
              target="_blank"
              rel="noopener noreferrer"
            >
              <span className="flex items-center gap-1.5 font-body font-bold text-sm text-accent uppercase tracking-wide transition-colors duration-[--duration-fast] group-hover/link:text-accent-hover">
                See on Github
                <GitHubIcon className="size-4 text-accent transition-colors duration-[--duration-fast] group-hover/link:text-accent-hover" />
              </span>
              <span className="h-0.5 w-full bg-accent/60 transition-all duration-[--duration-fast] ease-[--ease-out] group-hover/link:bg-accent-hover" />
            </a>
          )}
        </div>
      </div>
    </article>
  );
}
