import { SKILLS } from "@/lib/constants";
import { SkillChip } from "../ui/SkillChip";
import { ScrollReveal } from "../motion/ScrollReveal";
import { TextReveal } from "../motion/TextReveal";
import { BounceIn } from "../motion/BounceIn";

export function Skills() {
  return (
    <section
      aria-labelledby="skills-heading"
      id="skills"
      className="px-section-x md:px-section-x-md py-20 max-w-[1440px] mx-auto"
    >
      <div className="flex flex-col lg:flex-row gap-8 lg:gap-6">
        {/* Heading */}
        <ScrollReveal className="lg:flex-1">
          <h2
            id="skills-heading"
            className="font-display text-4xl md:text-5xl xl:text-[64px] text-text-primary leading-none"
          >
            <TextReveal>My Skills</TextReveal>
          </h2>
        </ScrollReveal>

        {/* Content */}
        <ScrollReveal delay={0.1} className="flex flex-col gap-8 lg:flex-1">
          <p className="font-body text-lg text-text-secondary leading-[1.6]">
            I am always looking to add more skills. Continuously learning and
            growing through hands-on projects and challenges.
          </p>

          <ul
            className="flex flex-wrap gap-4"
            role="list"
            aria-label="Technical skills"
          >
            {SKILLS.map((skill, index) => (
              <li key={skill.label}>
                <BounceIn delay={index * 0.08}>
                  <SkillChip label={skill.label} />
                </BounceIn>
              </li>
            ))}
          </ul>
        </ScrollReveal>
      </div>
    </section>
  );
}
